Lib version: 4.3.0

## Steps To Reproduce

<!-- The exact steps required to reproduce the issue, ideally with a code example -->

```javascript
const workbook = new ExcelJS.stream.xlsx.WorkbookWriter(options)
const sheet = workbook.addWorksheet(
    'my sheet', 
    { properties: { defaultRowHeight: 40, defaultColWidth: 30 } }
)
sheet.columns = [1,2,3,4].map(item => {
    return {
        header: item,
        key: item,
        width: item === 1 ? 7 : void 0
    }
})
[1,2,3,4,5,6].forEach((item, index) => {
    const row = sheet.addRow({ [item]: item })
    row.eachCell((v) => {
        v.style = {
            fill: {
                type: 'pattern',
                pattern:'darkTrellis',
                bgColor: { argb: 'FFFFFFFF' },
                fgColor:{ argb:'FFFFFFFF' }
            },
            font: {
                size: 11,
                color: { argb: 'FF000000' }
            },
            border: {
                top: { style:'thin', color: { argb:'FF1491ef' } },
                left: { style:'thin', color: { argb:'FF1491ef' } },
                bottom: { style:'thin', color: { argb:'FF1491ef' } },
                right: { style:'thin', color: { argb:'FF1491ef' } },
            },
            alignment: { vertical: 'middle', horizontal: 'center',  wrapText: true }
        }
    })
    row.commit()
})
sheet.commit()
await workbook.commit()
```

## The expected behaviour

First, i set the `defaultRowHeight` and `defaultColWidth`
i just set some columns and row, and then set fill, font, border, alignment.(the data is my product data)

Finally, i found some row can not apply the `defaultRowHeight`.

![image](https://user-images.githubusercontent.com/9781661/139644356-6c8d5ea7-4be5-47b8-8afe-9f5343436ade.png)

and then, i try to set the height for row, like `row.height = 40`, but i found the columns`s height become auto.

![image](https://user-images.githubusercontent.com/9781661/139644694-0722e1ae-e5ff-409e-9a35-012f929cb897.png)

so, is it a bug ? or can i set the column height, like `sheet.columns = [ { height: 40 } ]` ?

<!-- A clear and concise description of what you expected to happen. -->


